14	/// Split a record-label body `{...}|{...}|{...}` (already stripped of the outer
15	/// braces) at top-level `|`, honoring unescaped `{ }` nesting; escaped `\{ \} \|`
16	/// inside cell text are literal and ignored.
17	fn split_top_pipes(s: &str) -> Vec<String> {
18	    let mut out = Vec::new();
19	    let mut cur = String::new();
20	    let mut depth = 0i32;
21	    let bytes: Vec<char> = s.chars().collect();
22	    let mut i = 0;
23	    while i < bytes.len() {
24	        let c = bytes[i];
25	        if c == '\\' && i + 1 < bytes.len() {
26	            cur.push(c);
27	            cur.push(bytes[i + 1]);
28	            i += 2;
29	            continue;
30	        }
31	        match c {
32	            '{' => {
33	                depth += 1;
34	                cur.push(c);
35	            }
36	            '}' => {
37	                depth -= 1;
38	                cur.push(c);
39	            }
40	            '|' if depth == 0 => {
41	                out.push(std::mem::take(&mut cur));
42	            }
43	            _ => cur.push(c),
44	        }
45	        i += 1;
46	    }
47	    out.push(cur);
48	    out
49	}
