85	/// Dewrap a cell's wrapped bytes (with `\l` / `&nbsp;`, escaped) back to its flat,
86	/// un-escaped text, inverting the observed break joins (BEHAVIOR.md §3f):
87	/// a bare `,` line-end regains its dropped space, a `, ` line-end joins directly,
88	/// a peeled `>` joins directly, a peeled `)` regains its ` `.
89	fn dewrap(cell: &str) -> String {
90	    if !cell.contains("\\l") {
91	        return unescape(cell);
92	    }
93	    let raw_lines: Vec<&str> = cell.split("\\l").collect();
94	    // Drop the trailing empty piece after the final "\l".
95	    let mut lines: Vec<(bool, String)> = Vec::new();
96	    for (i, l) in raw_lines.iter().enumerate() {
97	        if i + 1 == raw_lines.len() && l.is_empty() {
98	            break;
99	        }
100	        // Strip leading &nbsp; runs, remembering whether the line was indented
101	        // (an indented closer peel loses no character; a col-0 `)` regains its
102	        // padding space).
103	        let mut rest = *l;
104	        let mut indented = false;
105	        while let Some(r) = rest.strip_prefix("&nbsp;") {
106	            rest = r;
107	            indented = true;
108	        }
109	        lines.push((indented, unescape(rest)));
110	    }
111	    if lines.is_empty() {
112	        return String::new();
113	    }
114	    let mut flat = lines[0].1.clone();
115	    for (indented, li) in &lines[1..] {
116	        if flat.ends_with(", ") {
117	            flat.push_str(li);
118	        } else if flat.ends_with(',') {
119	            flat.push(' ');
120	            flat.push_str(li);
121	        } else if li == ")" && !indented {
122	            flat.push_str(" )");
123	        } else {
124	            flat.push_str(li);
125	        }
126	    }
127	    flat
128	}
