//! Open-side whole-payload census harness (round-11).
//! Reconstructs every DOT payload by re-laying its record cells through the
//! clean engine's DEFAULT path (group_widths + wrap_cell_dot, NO width
//! overrides) and diffs byte-for-byte against the reference payload. Measures
//! (a) cell-level exactness, (b) record-level all-cells-exact, (c) whole-payload
//! byte-exactness, and classifies every divergence into families with a
//! first-diverging-byte witness. Computes INPUTS/measurements only; no clean
//! render logic is reimplemented here.

use graph_clean::doclayout::wrap_cell_dot;
use graph_clean::generate::group_widths;
use std::collections::BTreeMap;

fn split_top_pipes(s: &str) -> Vec<String> {
    let mut out = Vec::new();
    let mut cur = String::new();
    let mut depth = 0i32;
    let bytes: Vec<char> = s.chars().collect();
    let mut i = 0;
    while i < bytes.len() {
        let c = bytes[i];
        if c == '\\' && i + 1 < bytes.len() {
            cur.push(c);
            cur.push(bytes[i + 1]);
            i += 2;
            continue;
        }
        match c {
            '{' => { depth += 1; cur.push(c); }
            '}' => { depth -= 1; cur.push(c); }
            '|' if depth == 0 => { out.push(std::mem::take(&mut cur)); }
            _ => cur.push(c),
        }
        i += 1;
    }
    out.push(cur);
    out
}

fn strip_braces(s: &str) -> &str {
    let s = s.trim();
    let s = s.strip_prefix('{').unwrap_or(s);
    s.strip_suffix('}').unwrap_or(s)
}

fn unescape(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    let cs: Vec<char> = s.chars().collect();
    let mut i = 0;
    while i < cs.len() {
        if cs[i] == '\\' && i + 1 < cs.len() && matches!(cs[i + 1], '<' | '>' | '{' | '}' | '|') {
            out.push(cs[i + 1]);
            i += 2;
        } else {
            out.push(cs[i]);
            i += 1;
        }
    }
    out
}

/// Split a cell into (port_prefix, content) where port_prefix is "<nK> " or "".
fn split_port(cell: &str) -> (String, String) {
    let c = cell;
    let trimmed = c.trim_start();
    let lead_ws = &c[..c.len() - trimmed.len()];
    if let Some(rest) = trimmed.strip_prefix('<') {
        if let Some(gt) = rest.find('>') {
            let port = &trimmed[..gt + 1]; // <nK>
            let after = &rest[gt + 1..];
            if let Some(a2) = after.strip_prefix(' ') {
                return (format!("{}{} ", lead_ws, port), a2.to_string());
            }
            return (format!("{}{}", lead_ws, port), after.to_string());
        }
    }
    (String::new(), c.to_string())
}

fn dewrap(cell: &str) -> String {
    if !cell.contains("\\l") {
        return unescape(cell);
    }
    let raw_lines: Vec<&str> = cell.split("\\l").collect();
    let mut lines: Vec<(bool, String)> = Vec::new();
    for (i, l) in raw_lines.iter().enumerate() {
        if i + 1 == raw_lines.len() && l.is_empty() {
            break;
        }
        let mut rest = *l;
        let mut indented = false;
        while let Some(r) = rest.strip_prefix("&nbsp;") {
            rest = r;
            indented = true;
        }
        lines.push((indented, unescape(rest)));
    }
    if lines.is_empty() {
        return String::new();
    }
    let mut flat = lines[0].1.clone();
    for (indented, li) in &lines[1..] {
        if flat.ends_with(", ") {
            flat.push_str(li);
        } else if flat.ends_with(',') {
            flat.push(' ');
            flat.push_str(li);
        } else if li == ")" && !indented {
            flat.push_str(" )");
        } else {
            flat.push_str(li);
        }
    }
    flat
}

/// Parse legend alias names (the `<FONT COLOR="#000000">NAME</FONT> ... =` rows).
fn legend_aliases(dot: &str) -> Vec<String> {
    let mut out = Vec::new();
    for line in dot.lines() {
        if !line.contains("</FONT></TD>") {
            continue;
        }
        // rows of form: <FONT COLOR="#000000">NAME</FONT></TD> <TD...>=</TD>
        let mut rest = line;
        while let Some(p) = rest.find("#000000\">") {
            let after = &rest[p + "#000000\">".len()..];
            if let Some(e) = after.find("</FONT>") {
                let name = &after[..e];
                // aliases are short identifiers (letters+digits+dots)
                if !name.is_empty()
                    && name.chars().all(|c| c.is_ascii_alphanumeric() || c == '.' )
                    && name.chars().next().map(|c| c.is_ascii_uppercase()).unwrap_or(false)
                {
                    out.push(name.to_string());
                }
                rest = &after[e + 7..];
            } else {
                break;
            }
        }
    }
    out
}

/// Each record label body between `label="` and `",fillcolor=`.
fn each_record_label(dot: &str) -> Vec<String> {
    let mut out = Vec::new();
    for line in dot.lines() {
        if !line.contains("shape=\"record\"") {
            continue;
        }
        if let Some(start) = line.find("label=\"") {
            let after = &line[start + 7..];
            if let Some(end) = after.find("\",fillcolor=") {
                out.push(after[..end].to_string());
            }
        }
    }
    out
}

struct CellDiverge {
    family: &'static str,
    abbreviated: bool,
    flat: String,
    got: String,
    raw: String,
    first_byte: usize,
}

fn first_diff_byte(a: &str, b: &str) -> usize {
    let ab = a.as_bytes();
    let bb = b.as_bytes();
    let n = ab.len().min(bb.len());
    let mut i = 0;
    while i < n && ab[i] == bb[i] {
        i += 1;
    }
    i
}

/// Reconstruct one record label by re-laying its cells; returns (reconstructed,
/// cell divergences, per-cell stats: (all_pc, all_pc_ok, wrap, wrap_ok, info_ok,
/// rec_ok, skipped)).
struct RecOut {
    rebuilt: String,
    diverges: Vec<CellDiverge>,
    all_pc: u64,
    all_pc_ok: u64,
    wrap: u64,
    wrap_ok: u64,
    info_ok: bool,
    rec_ok: bool,
    parsed: bool,
}

fn is_abbrev(cell: &str, aliases: &[String]) -> bool {
    aliases.iter().any(|a| {
        // token-boundary match
        let mut idx = 0;
        while let Some(p) = cell[idx..].find(a.as_str()) {
            let s = idx + p;
            let e = s + a.len();
            let before_ok = s == 0 || !cell.as_bytes()[s - 1].is_ascii_alphanumeric();
            let after_ok = e >= cell.len()
                || !(cell.as_bytes()[e].is_ascii_alphanumeric() || cell.as_bytes()[e] == b'.');
            if before_ok && after_ok {
                return true;
            }
            idx = s + 1;
            if idx >= cell.len() { break; }
        }
        false
    })
}

fn process_record(label_body: &str, aliases: &[String]) -> RecOut {
    let inner = strip_braces(label_body);
    let groups = split_top_pipes(inner);
    // parse each group into cells (port, content)
    let mut group_cells: Vec<Vec<(String, String)>> = Vec::new();
    for g in &groups {
        let gi = strip_braces(g);
        let cells = split_top_pipes(gi);
        group_cells.push(cells.iter().map(|c| split_port(c)).collect());
    }
    // locate info group
    let mut info_idx = None;
    for (i, g) in group_cells.iter().enumerate() {
        if g.first().map(|c| c.1.trim_start().starts_with('#')).unwrap_or(false) {
            info_idx = Some(i);
            break;
        }
    }
    let Some(info_idx) = info_idx else {
        return RecOut { rebuilt: label_body.to_string(), diverges: vec![], all_pc: 0, all_pc_ok: 0, wrap: 0, wrap_ok: 0, info_ok: true, rec_ok: false, parsed: false };
    };

    // premise cells (all groups before info), conclusion cells (after)
    let prem_flats: Vec<String> = group_cells[..info_idx].iter().flatten().map(|(_, c)| dewrap(c)).collect();
    let concl_flats: Vec<String> = group_cells[info_idx + 1..].iter().flatten().map(|(_, c)| dewrap(c)).collect();
    let prem_w = group_widths(&prem_flats);
    let concl_w = group_widths(&concl_flats);

    let mut diverges = Vec::new();
    let mut all_pc = 0u64;
    let mut all_pc_ok = 0u64;
    let mut wrap = 0u64;
    let mut wrap_ok = 0u64;
    let mut rec_ok = true;
    let mut info_ok = true;

    let mut pw = 0usize;
    let mut cw = 0usize;
    let mut rebuilt_groups: Vec<String> = Vec::new();

    for (gi, cells) in group_cells.iter().enumerate() {
        let mut rebuilt_cells: Vec<String> = Vec::new();
        for (port, content) in cells {
            let flat = dewrap(content);
            let (got, is_info) = if gi == info_idx {
                (wrap_cell_dot(&flat, 87), true)
            } else if gi < info_idx {
                let w = prem_w[pw] as isize;
                pw += 1;
                (wrap_cell_dot(&flat, w), false)
            } else {
                let w = concl_w[cw] as isize;
                cw += 1;
                (wrap_cell_dot(&flat, w), false)
            };
            rebuilt_cells.push(format!("{}{}", port, got));

            let raw = content.clone();
            if is_info {
                if got == raw {
                    // ok
                } else {
                    info_ok = false;
                    rec_ok = false;
                    let gw = got.contains("\\l");
                    let rw = raw.contains("\\l");
                    let fam = classify(gw, rw);
                    diverges.push(CellDiverge {
                        family: fam,
                        abbreviated: is_abbrev(&raw, aliases),
                        flat: flat.clone(),
                        first_byte: first_diff_byte(&got, &raw),
                        got, raw,
                    });
                }
            } else {
                all_pc += 1;
                let rw = raw.contains("\\l");
                if rw { wrap += 1; }
                if got == raw {
                    all_pc_ok += 1;
                    if rw { wrap_ok += 1; }
                } else {
                    rec_ok = false;
                    let gw = got.contains("\\l");
                    let fam = classify(gw, rw);
                    diverges.push(CellDiverge {
                        family: fam,
                        abbreviated: is_abbrev(&raw, aliases),
                        flat: flat.clone(),
                        first_byte: first_diff_byte(&got, &raw),
                        got, raw,
                    });
                }
            }
        }
        rebuilt_groups.push(format!("{{{}}}", rebuilt_cells.join("|")));
    }
    let rebuilt = format!("{{{}}}", rebuilt_groups.join("|"));
    RecOut { rebuilt, diverges, all_pc, all_pc_ok, wrap, wrap_ok, info_ok, rec_ok, parsed: true }
}

fn classify(got_wraps: bool, raw_wraps: bool) -> &'static str {
    match (got_wraps, raw_wraps) {
        (true, true) => "fill",             // both wrap, different break
        (false, true) => "trigger_false_neg", // clean flat, HS wraps
        (true, false) => "trigger_false_pos", // clean wraps, HS flat
        (false, false) => "flat_both_differ", // neither wraps but content differs
    }
}

fn main() {
    let dir = std::env::var("GRAPHCLEAN_CORPUS").expect("set GRAPHCLEAN_CORPUS");
    let mut files: Vec<_> = std::fs::read_dir(&dir)
        .expect("read corpus dir")
        .filter_map(|e| e.ok())
        .map(|e| e.path())
        .filter(|p| p.extension().map(|x| x == "dot").unwrap_or(false))
        .collect();
    files.sort();

    // cell/record cross-validation totals
    let mut all_pc = 0u64;
    let mut all_pc_ok = 0u64;
    let mut wrap = 0u64;
    let mut wrap_ok = 0u64;
    let mut info_cells = 0u64;
    let mut info_ok = 0u64;
    let mut records = 0u64;
    let mut records_ok = 0u64;

    // whole-payload
    let mut payloads = 0u64;
    let mut payloads_exact = 0u64;
    let mut payloads_with_skips = 0u64;
    let mut payloads_exact_strict = 0u64; // exact AND no skipped record

    // family aggregation
    // key: (family, abbreviated)
    let mut fam: BTreeMap<(&'static str, bool), u64> = BTreeMap::new();
    // one witness per family key
    let mut fam_witness: BTreeMap<(&'static str, bool), (String, String, String, usize)> = BTreeMap::new();

    for path in &files {
        let dot = std::fs::read_to_string(path).unwrap();
        let aliases = legend_aliases(&dot);
        payloads += 1;
        let mut file_exact = true;
        let mut file_skipped = false;

        // process each record label; reconstruct and compare to original
        for label in each_record_label(&dot) {
            let out = process_record(&label, &aliases);
            if !out.parsed {
                file_skipped = true;
                continue;
            }
            records += 1;
            info_cells += 1;
            if out.info_ok { info_ok += 1; }
            all_pc += out.all_pc;
            all_pc_ok += out.all_pc_ok;
            wrap += out.wrap;
            wrap_ok += out.wrap_ok;
            if out.rec_ok { records_ok += 1; }

            if out.rebuilt != label {
                file_exact = false;
            }
            for d in &out.diverges {
                *fam.entry((d.family, d.abbreviated)).or_insert(0) += 1;
                fam_witness.entry((d.family, d.abbreviated)).or_insert_with(|| {
                    (d.flat.clone(), d.got.clone(), d.raw.clone(), d.first_byte)
                });
            }
        }
        if file_skipped { payloads_with_skips += 1; }
        if file_exact { payloads_exact += 1; }
        if file_exact && !file_skipped { payloads_exact_strict += 1; }
    }

    let pct = |a: u64, b: u64| if b == 0 { 0.0 } else { 100.0 * a as f64 / b as f64 };
    println!("=== ROUND-11 WHOLE-PAYLOAD CENSUS over {} files ===", files.len());
    println!("(a) ALL prem/concl cells byte-exact: {}/{} = {:.3}%", all_pc_ok, all_pc, pct(all_pc_ok, all_pc));
    println!("    wrapping prem/concl cells:        {}/{} = {:.3}%", wrap_ok, wrap, pct(wrap_ok, wrap));
    println!("    info cells:                       {}/{} = {:.3}%", info_ok, info_cells, pct(info_ok, info_cells));
    println!("(b) RECORDS all-cells-exact:          {}/{} = {:.3}%", records_ok, records, pct(records_ok, records));
    println!("(c) WHOLE-PAYLOAD byte-exact (lenient, ignore unparsed recs): {}/{} = {:.3}%", payloads_exact, payloads, pct(payloads_exact, payloads));
    println!("(c) WHOLE-PAYLOAD byte-exact (strict, unparsed rec => fail):  {}/{} = {:.3}%", payloads_exact_strict, payloads, pct(payloads_exact_strict, payloads));
    println!("    payloads with >=1 unparsed record: {}", payloads_with_skips);
    println!();
    println!("=== DIVERGENCE FAMILIES (cell-level, ranked) ===");
    let mut famv: Vec<_> = fam.iter().collect();
    famv.sort_by(|a, b| b.1.cmp(a.1));
    for ((f, ab), n) in famv {
        let w = fam_witness.get(&(*f, *ab)).unwrap();
        let flat = if w.0.len() > 70 { format!("{}...", &w.0[..70]) } else { w.0.clone() };
        println!("{:>7} x  {}{}", n, f, if *ab { " [ABBREV]" } else { "" });
        println!("           flat: {}", flat);
        println!("           first-diverge-byte: {}", w.3);
        // trimmed got/raw around the divergence
        let show = |s: &str| -> String {
            let s = s.replace("&nbsp;", "·").replace("\\l", "|");
            if s.len() > 90 { format!("{}...", &s[..90]) } else { s }
        };
        println!("           HS : {}", show(&w.2));
        println!("           got: {}", show(&w.1));
    }
}

